import{_ as t,o as e,c as a,S as r}from"./chunks/framework.7245853a.js";const g=JSON.parse('{"title":"🍞 常用轮子","description":"","frontmatter":{"sticky":2,"title":"🍞 常用轮子","tag":["组件库"],"top":4,"sidebar":true},"headers":[],"relativePath":"basic-tools/常用轮子汇总.md","filePath":"basic-tools/常用轮子汇总.md","lastUpdated":null}'),l={name:"basic-tools/常用轮子汇总.md"},o=r('<p><img src="https://www.z4a.net/images/2023/10/07/48daa38da2d35ca476f3823e5b12721d.png" alt="48daa38da2d35ca476f3823e5b12721d.png"></p><h3 id="react-ui组件库" tabindex="-1">React UI组件库 <a class="header-anchor" href="#react-ui组件库" aria-label="Permalink to &quot;React UI组件库&quot;">​</a></h3><ol><li>Ant Design ：文档齐全，社区生态良好，有手机版，还有PC版。可以用来快速创建手机/后台/内部应用的UI组件库。我的博客，就是那这个组件库制作的。</li></ol><p>网址：<a href="https://ant.design/" target="_blank" rel="noreferrer">https://ant.design/</a></p><ol start="2"><li>React Bootstrap : 虽然UI设计上没什么出彩，但是快速完成个人小项目已经足够了。</li></ol><p>网址：<a href="https://react-bootstrap.github.io/" target="_blank" rel="noreferrer">https://react-bootstrap.github.io/</a></p><ol start="3"><li>MATERIAL-UI：实现了Google的Material Design 全新设计语言的React组件库。在Github上有超过5万star，最受欢迎的React组件库之一。现在也叫做Mui。</li></ol><p>网址：<a href="http://material-ui.com/" target="_blank" rel="noreferrer">material-ui.com/</a> or <a href="https://mui.com/zh/" target="_blank" rel="noreferrer">https://mui.com/zh/</a></p><h3 id="vue-ui组件库" tabindex="-1">Vue UI组件库 <a class="header-anchor" href="#vue-ui组件库" aria-label="Permalink to &quot;Vue UI组件库&quot;">​</a></h3><ol start="4"><li>Element ： 国内最流行的Vue UI组件库，文档完整，支持在Vue3下使用。而且Element还提供了Element-React版本和Element-Angular版本。也就是说你掌握一套UI，可以在主流的前端开发框架中使用，如果你只学一套UI组件库，学这个就没错了。</li></ol><p>网址：<a href="https://element.eleme.io/#/zh-CN" target="_blank" rel="noreferrer">https://element.eleme.io/#/zh-CN</a></p><ol start="5"><li>vant ：有赞公司旗下的开源组件库，适用于移动端开发。组件齐全，使用简单，UI设计也非常漂亮。</li></ol><p>网址：<a href="http://youzan.github.io/vant/#/zh-C%E2%80%A6" target="_blank" rel="noreferrer">youzan.github.io/vant/#/zh-C…</a></p><ol start="6"><li>View UI： 有免费版和专业版（也就是收费版）。</li></ol><p>网址：<a href="http://www.iviewui.com/" target="_blank" rel="noreferrer">www.iviewui.com/</a></p><h3 id="动画库" tabindex="-1">动画库 <a class="header-anchor" href="#动画库" aria-label="Permalink to &quot;动画库&quot;">​</a></h3><p>如果想页面制作的好看，动画效果一定是少不了的。所以必须推荐动画插件。</p><ul><li><p>Animate.css 纯css的动画库，所以无论你前端使用什么框架，都可以非常方便的使用它，内置了超多的动画效果，并且预览起来也非常方便。</p><p>网址：<a href="https://animate.style/" target="_blank" rel="noreferrer">https://animate.style/</a></p></li></ul><h3 id="常用效果组件" tabindex="-1">常用效果组件 <a class="header-anchor" href="#常用效果组件" aria-label="Permalink to &quot;常用效果组件&quot;">​</a></h3><p>所有介绍了一些UI组件库，组件库的组件大而全，但精细程度有时候是不够的，所以有时候我们还需要一些小而精的专属组件。</p><ol start="7"><li></li></ol><p>轮播图组件：swiper，这个提供的轮播图效果太多了，中文文档齐全，还有交流QQ群。支持原生、JQuery、Vue、React、Angular等，任何前端开发场景中使用。而且还有PC端和移动端。比较讨厌的是官网有很多弹出广告，但也能理解，为了生存吗。</p><p>网址：<a href="https://www.swiper.com.cn/" target="_blank" rel="noreferrer">https://www.swiper.com.cn/</a></p><ol start="8"><li>滚动插件：mescroll.js , 移动端的滚动经常会出现不流畅，延迟等问题。我也尝试着去使用了很多大神些的滚动插件，多方比较，我选定了这款插件。他是基于H5的，不依赖来与其它前端框架，侵入性很小，实用性很大。如果你在滚动中遇到了问题，可以使用这个插件来解决。</li></ol><p>网址：<a href="http://www.mescroll.com/api.html" target="_blank" rel="noreferrer">http://www.mescroll.com/api.html</a></p><h3 id="工具类轮子" tabindex="-1">工具类轮子 <a class="header-anchor" href="#工具类轮子" aria-label="Permalink to &quot;工具类轮子&quot;">​</a></h3><p>开发中除了界面的制作，也需要一些工具类的轮子，下面就介绍一下我开发中使用的一些工具类轮子。</p><ol start="9"><li>函数库：lodash.js ,是一个一致性、模块化、高性能的JavaScript实用工具库。这个函数库可以在原生JS中使用，也可以在React和Vue中使用。几乎你开发中所有的函数，这个库都给你写好。你需要作的就是熟练和恰到好处的使用。</li></ol><p>网址：<a href="https://www.lodashjs.com/" target="_blank" rel="noreferrer">https://www.lodashjs.com/</a></p><ol start="10"><li>函数库：Day.js , 它是一个极简的JavaScript库，可以为你很好的验证、操作和显示日期和时间。</li></ol><p>网址：<a href="https://dayjs.fenxianglu.cn/" target="_blank" rel="noreferrer">https://dayjs.fenxianglu.cn/</a></p><ol start="11"><li>timeago.js，它是显示几小时之前，很多随时更新的网站和应用，为了显示出及时性，不再显示具体发布的时间，而是改为几分钟或者几小时前发布的。这样显着时效性更好。这个插件的作用就是这个。如果需要，请收藏好。</li></ol><p>网址：<a href="https://github.com/hustcc/timeago.js" target="_blank" rel="noreferrer">https://github.com/hustcc/timeago.js</a></p><ol start="12"><li>echarts 数据可视化： 我们公司的所有数据可视化插件都使用的这个组件库，可以满足企业级开发的需求。这个也算是国内最好的可视化开发组件库了。</li></ol><p>网址：<a href="https://echarts.apache.org/zh/index.html" target="_blank" rel="noreferrer">https://echarts.apache.org/zh/index.html</a></p><ol start="13"><li>Markdown编辑器： Markdown ，作为程序员，编写Markdown格式的文档已经是必会技能了，所以如果是为程序员开发的应用和网站，一定要支持Markdown功能。我在选择Markdown编辑器时踩了很多坑，最终才找到了这款好用的组件。</li></ol><p>网址：<a href="https://pandao.github.io/editor.md/" target="_blank" rel="noreferrer">https://pandao.github.io/editor.md/</a></p><ol start="14"><li>表单验证：validator.js ，这个组件我想大部分人都用过，因为无论时用户端，还是管理端前台开发验证都时必须的，无论是公司，还是个人。我都一直在使用这个验证插件。</li></ol><p>网址:<a href="https://github.com/validatorjs/validator.js" target="_blank" rel="noreferrer">https://github.com/validatorjs/validator.js</a></p><ol start="15"><li>Vue拖拽组件 ：vue-draggable, 用于现在开发的应用都需要有移动端，所以拖拽操作越来越多了，它是我目前看到的基于Vue的最好拖拽组件。</li></ol><p>网址：<a href="https://www.itxst.com/vue-draggable/tutorial.html" target="_blank" rel="noreferrer">https://www.itxst.com/vue-draggable/tutorial.html</a></p><ol start="16"><li>Vue生成二维码：vue-qr 如果你需要生成二维码，用这个组件绝对没错，公司的项目一直在使用，可以方便快捷的生成任何形式的二维码。包括彩色和自定义样式。</li></ol><p>网址：<a href="https://www.npmjs.com/package/vue-qr" target="_blank" rel="noreferrer">https://www.npmjs.com/package/vue-qr</a></p><ol start="17"><li>Vue图片剪裁 ： vue-cropper 无论开发任何应用，都需要用户上传图片。但又为了保持页面的一致性，所以要对上传的图片，安装设计规范，进行裁切。这时候你就可以使用这个组件了。</li></ol><p>网址：<a href="https://github.com/xyxiao001/vue-cropper" target="_blank" rel="noreferrer">https://github.com/xyxiao001/vue-cropper</a></p><ol start="18"><li>图片懒加载：vue-lazyload 其实很多UI组件库已经有这个图片懒加载的给功能了，但是还是单独提出来一下，因为它不会和其它Vue组件库冲突，而且功能更多。</li></ol><p>网址：<a href="https://www.npmjs.com/package/vue-lazyload" target="_blank" rel="noreferrer">https://www.npmjs.com/package/vue-lazyload</a></p><ol start="19"><li>Vue上传组件：vue-simple-upload 上传也是我们绕不开的开发需求，所以你必须拥有一个完全好用的上传组件。它非常好用，但缺点是没有官方网站，只有一个Github地址。</li></ol><p>网址：<a href="https://github.com/saivarunk/vue-simple-upload" target="_blank" rel="noreferrer">https://github.com/saivarunk/vue-simple-upload</a></p>',49),i=[o];function s(p,h,n,c,u,m){return e(),a("div",null,i)}const f=t(l,[["render",s]]);export{g as __pageData,f as default};
